    32	static void ue_context_setup_response_f1ap(const f1ap_ue_context_setup_t *req, const f1ap_ue_context_setup_t *resp)
    33	{
    34	  DevAssert(req->drbs_to_be_setup_length == resp->drbs_to_be_setup_length);
    35	  AssertFatal(req->drbs_to_be_setup_length == 0, "not implmented\n");
    36	
    37	  DevAssert(req->srbs_to_be_setup_length == resp->srbs_to_be_setup_length);
    38	  MessageDef *msg = itti_alloc_new_message (TASK_MAC_GNB, 0, F1AP_UE_CONTEXT_SETUP_RESP);
    39	  f1ap_ue_context_setup_t *f1ap_msg = &F1AP_UE_CONTEXT_SETUP_RESP(msg);
    40	  /* copy all fields, but reallocate rrc_containers! */
    41	  *f1ap_msg = *resp;
    42	
    43	  if (resp->srbs_to_be_setup_length > 0) {
    44	    DevAssert(resp->srbs_to_be_setup != NULL);
    45	    f1ap_msg->srbs_to_be_setup_length = resp->srbs_to_be_setup_length;
    46	    f1ap_msg->srbs_to_be_setup = calloc(f1ap_msg->srbs_to_be_setup_length, sizeof(*f1ap_msg->srbs_to_be_setup));
    47	    for (int i = 0; i < f1ap_msg->srbs_to_be_setup_length; ++i)
    48	      f1ap_msg->srbs_to_be_setup[i] = resp->srbs_to_be_setup[i];
    49	  }
    50	
    51	  f1ap_msg->du_to_cu_rrc_information = malloc(sizeof(*resp->du_to_cu_rrc_information));
    52	  AssertFatal(f1ap_msg->du_to_cu_rrc_information != NULL, "out of memory\n");
    53	  f1ap_msg->du_to_cu_rrc_information_length = resp->du_to_cu_rrc_information_length;
    54	  du_to_cu_rrc_information_t *du2cu = f1ap_msg->du_to_cu_rrc_information;
    55	  du2cu->cellGroupConfig_length = resp->du_to_cu_rrc_information->cellGroupConfig_length;
    56	  du2cu->cellGroupConfig = calloc(du2cu->cellGroupConfig_length, sizeof(*du2cu->cellGroupConfig));
    57	  AssertFatal(du2cu->cellGroupConfig != NULL, "out of memory\n");
    58	  memcpy(du2cu->cellGroupConfig, resp->du_to_cu_rrc_information->cellGroupConfig, du2cu->cellGroupConfig_length);
    59	
    60	  itti_send_msg_to_task(TASK_DU_F1, 0, msg);
    61	}
