   117	static void initial_ul_rrc_message_transfer_f1ap(module_id_t module_id, const f1ap_initial_ul_rrc_message_t *ul_rrc)
   118	{
   119	  MessageDef *msg = itti_alloc_new_message(TASK_MAC_GNB, 0, F1AP_INITIAL_UL_RRC_MESSAGE);
   120	  /* copy all fields, but reallocate rrc_containers! */
   121	  f1ap_initial_ul_rrc_message_t *f1ap_msg = &F1AP_INITIAL_UL_RRC_MESSAGE(msg);
   122	  *f1ap_msg = *ul_rrc;
   123	
   124	  f1ap_msg->rrc_container = malloc(ul_rrc->rrc_container_length);
   125	  DevAssert(f1ap_msg->rrc_container);
   126	  memcpy(f1ap_msg->rrc_container, ul_rrc->rrc_container, ul_rrc->rrc_container_length);
   127	  f1ap_msg->rrc_container_length = ul_rrc->rrc_container_length;
   128	
   129	  f1ap_msg->du2cu_rrc_container = malloc(ul_rrc->du2cu_rrc_container_length);
   130	  DevAssert(f1ap_msg->du2cu_rrc_container);
   131	  memcpy(f1ap_msg->du2cu_rrc_container, ul_rrc->du2cu_rrc_container, ul_rrc->du2cu_rrc_container_length);
   132	  f1ap_msg->du2cu_rrc_container_length = ul_rrc->du2cu_rrc_container_length;
   133	
   134	  itti_send_msg_to_task(TASK_DU_F1, module_id, msg);
   135	}
