   137	void mac_rrc_ul_f1ap_init(struct nr_mac_rrc_ul_if_s *mac_rrc)
   138	{
   139	  mac_rrc->ue_context_setup_response = ue_context_setup_response_f1ap;
   140	  mac_rrc->ue_context_modification_response = ue_context_modification_response_f1ap;
   141	  mac_rrc->ue_context_release_request = ue_context_release_request_f1ap;
   142	  mac_rrc->ue_context_release_complete = ue_context_release_complete_f1ap;
   143	  mac_rrc->initial_ul_rrc_message_transfer = initial_ul_rrc_message_transfer_f1ap;
   144	}
